fn c2Clip(seg: &mut [c2v], h: c2h) -> i32 {
    let mut out = [c2v { x: 0.0, y: 0.0 }; 2];
    let mut sp: usize = 0;

    let d0 = c2Dist(h, seg[0]);
    if d0 < 0.0 {
        out[sp] = seg[0];
        sp += 1;
    }

    let d1 = c2Dist(h, seg[1]);
    if d1 < 0.0 {
        if sp < 2 {
            out[sp] = seg[1];
            sp += 1;
        }
    }

    if d0 == 0.0 && d1 == 0.0 {
        out[0] = seg[0];
        out[1] = seg[1];
        sp = 2;
    } else if d0 * d1 <= 0.0 {
        if sp < 2 {
            out[sp] = c2Intersect(seg[0], seg[1], d0, d1);
            sp += 1;
        }
    }

    seg[0] = out[0];
    seg[1] = out[1];
    sp as i32
}

